import React, { useState, useEffect, useContext } from 'react';
import axios from 'axios';
import { AuthContext } from '../context/AuthContext';

const BookAppointment = () => {
  const { user } = useContext(AuthContext);
  const [formData, setFormData] = useState({ doctor: '', date: '', time: '' });
  const [doctors, setDoctors] = useState([]);
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  // Fetch doctors when the component mounts
  useEffect(() => {
    const fetchDoctors = async () => {
      try {
        const res = await axios.get('/api/user/doctors', { withCredentials: true });
        setDoctors(res.data);
      } catch (err) {
        setError('Failed to load doctors.');
      }
    };

    if (user?.role === 'User' || user?.role === 'Admin') {
      fetchDoctors();
    }
  }, [user]);

  const handleChange = (e) => {
    setFormData((prev) => ({ ...prev, [e.target.name]: e.target.value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');
    setLoading(true);

    if (!user) {
      setError('You must be logged in to book an appointment.');
      return;
    }

    try {
      const appointmentDate = new Date(`${formData.date}T${formData.time}:00`);

      await axios.post(
          '/api/bookings',
          { doctor: formData.doctor, appointmentDate },
          { withCredentials: true }
      );

      setMessage('Appointment booked successfully!');
      setFormData({ doctor: '', date: '', time: '' });

      // Notify other parts of the app
      window.dispatchEvent(new Event('appointment-booked'));
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to book appointment.');
    } finally {
      setLoading(false);
    }
  };

  if (user?.role === 'Doctor') {
    return (
        <div className="text-red-600 text-center mt-24 text-xl font-semibold">
          Access Denied: Doctors are not allowed to book appointments.
        </div>
    );
  }

  return (
      <div className="min-h-screen bg-gradient-to-br from-green-50 to-blue-50 flex justify-center items-start pt-20 px-4 sm:px-0">
        <div className="bg-white shadow-lg rounded-xl p-8 w-full max-w-xl border border-gray-200">
          <h1 className="text-3xl font-bold text-center text-blue-700 mb-6">
            Book an Appointment
          </h1>

          {message && (
              <div className="bg-green-100 border border-green-400 text-green-700 p-3 rounded mb-4 text-center font-medium">
                {message}
              </div>
          )}
          {error && (
              <div className="bg-red-100 border border-red-400 text-red-700 p-3 rounded mb-4 text-center font-medium">
                {error}
              </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-5">
            {/* Doctor Dropdown */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Select Doctor</label>
              <select
                  name="doctor"
                  value={formData.doctor}
                  onChange={handleChange}
                  required
                  className="w-full border border-gray-300 text-black rounded px-3 py-2 focus:ring-2 focus:ring-blue-500"
              >
                <option value="">-- Choose a Doctor --</option>
                {doctors.map((doc) => (
                    <option key={doc._id} value={doc._id}>
                      Dr. {doc.username} ({doc.specialization || 'General'})
                    </option>
                ))}
              </select>
            </div>

            {/* Date Input */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Select Date</label>
              <input
                  type="date"
                  name="date"
                  value={formData.date}
                  onChange={handleChange}
                  required
                  min={new Date().toISOString().split('T')[0]}
                  className="w-full border border-gray-300 rounded text-black px-3 py-2 focus:ring-2 focus:ring-blue-500"
              />
            </div>

            {/* Time Input */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Select Time</label>
              <input
                  type="time"
                  name="time"
                  value={formData.time}
                  onChange={handleChange}
                  required
                  className="w-full border border-gray-300 text-black rounded px-3 py-2 focus:ring-2 focus:ring-blue-500"
              />
            </div>

            <button
                type="submit"
                disabled={loading}
                className={`w-full ${
                    loading ? 'bg-blue-300' : 'bg-blue-600 hover:bg-blue-700'
                } text-white font-semibold py-2 rounded transition-all`}
            >
              {loading ? 'Booking...' : 'Book Appointment'}
            </button>
          </form>
        </div>
      </div>
  );
};

export default BookAppointment;
